import{bQ as d,aL as a,u as r,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"高可用和容灾","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/15-高可用和容灾.md","filePath":"00.互联网与架构基础/15-高可用和容灾.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/15-高可用和容灾.md"};function o(p,t,l,i,n,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="高可用和容灾" tabindex="-1">高可用和容灾 <a class="header-anchor" href="#高可用和容灾" aria-label="Permalink to &quot;高可用和容灾&quot;">​</a></h1><p>一台机器坏了，服务还能不能继续用，这是高可用关心的事。一个机房坏了、一个城市的线路出问题、云区域不可用，系统还能不能恢复，这是容灾关心的事。</p><p>高可用通常处理“局部坏了怎么办”，容灾处理“坏得更大怎么办”。两者都离不开备份、切换、数据同步和演练。</p><h2 id="一、rto-和-rpo" tabindex="-1">一、RTO 和 RPO <a class="header-anchor" href="#一、rto-和-rpo" aria-label="Permalink to &quot;一、RTO 和 RPO&quot;">​</a></h2><p>容灾里常见两个指标：RTO 和 RPO。</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td>RTO</td><td>故障发生后，业务恢复需要多久</td></tr><tr><td>RPO</td><td>故障发生后，最多能丢多少数据</td></tr></tbody></table><p>RTO 越短，恢复越快。RPO 越小，数据丢失越少。两者越严格，成本和实现难度越高。</p><p>如果系统每天凌晨备份一次，上午 10 点故障后只能恢复到凌晨备份，那么 RPO 可能接近 10 小时。如果恢复过程需要 2 小时，RTO 就是 2 小时左右。</p><h2 id="二、备份恢复" tabindex="-1">二、备份恢复 <a class="header-anchor" href="#二、备份恢复" aria-label="Permalink to &quot;二、备份恢复&quot;">​</a></h2><p>备份是容灾底线。没有备份，误删、勒索、存储损坏、同步误操作都可能无法恢复。</p><p>备份要关注几个点：</p><table tabindex="0"><thead><tr><th>事项</th><th>说明</th></tr></thead><tbody><tr><td>备份频率</td><td>每小时、每天或按业务要求</td></tr><tr><td>保留周期</td><td>保留几天、几周、几个月</td></tr><tr><td>异地保存</td><td>避免源站和备份一起损坏</td></tr><tr><td>恢复演练</td><td>确认备份真的能恢复</td></tr><tr><td>权限隔离</td><td>防止误删生产时也删掉备份</td></tr></tbody></table><p>备份文件存在，不代表能在目标环境恢复成功，也不代表恢复后的数据满足业务要求。恢复演练很重要。</p><h2 id="三、主备和异地备" tabindex="-1">三、主备和异地备 <a class="header-anchor" href="#三、主备和异地备" aria-label="Permalink to &quot;三、主备和异地备&quot;">​</a></h2><p>主备通常处理单组件或单机房内的故障。异地备则把备份或副本放到另一个地理位置。</p><table tabindex="0"><thead><tr><th>形态</th><th>特点</th></tr></thead><tbody><tr><td>本地主备</td><td>切换快，适合单机或单组件故障</td></tr><tr><td>异地备份</td><td>成本较低，恢复时间较长</td></tr><tr><td>异地热备</td><td>备站持续同步，切换更快</td></tr><tr><td>异地冷备</td><td>平时不运行或低配运行，恢复时拉起</td></tr></tbody></table><p>异地备的关键是数据同步和入口切换。数据同步慢，RPO 就大；入口切换慢，RTO 就长。</p><h2 id="四、同城双活" tabindex="-1">四、同城双活 <a class="header-anchor" href="#四、同城双活" aria-label="Permalink to &quot;四、同城双活&quot;">​</a></h2><p>同城双活通常指同一个城市里的两个机房同时承载业务。两个机房距离近，网络延迟低，适合做更紧密的数据同步和流量分担。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20GLB%5B%22%E5%85%A8%E5%B1%80%E5%85%A5%E5%8F%A3%22%5D%0A%20%20A%5B%22%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BF%20A%22%5D%0A%20%20B%5B%22%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BF%20B%22%5D%0A%20%20Data%5B%22%E6%95%B0%E6%8D%AE%E5%90%8C%E6%AD%A5%22%5D%0A%0A%20%20User%20--%3E%20GLB%0A%20%20GLB%20--%3E%20A%0A%20%20GLB%20--%3E%20B%0A%20%20A%20%3C--%3E%20Data%0A%20%20B%20%3C--%3E%20Data%0A"></div><p>同城双活适合处理单机房故障、网络设备故障、局部供电故障。两边同时接流量，切换时不需要从零拉起备站。</p><p>难点在数据。读多写少系统比较容易做双活，强一致写入系统要谨慎。两边同时写同一份数据时，冲突处理会很复杂。</p><h2 id="五、异地双活" tabindex="-1">五、异地双活 <a class="header-anchor" href="#五、异地双活" aria-label="Permalink to &quot;五、异地双活&quot;">​</a></h2><p>异地双活把不同城市或区域同时作为业务入口。它能抵御城市级或区域级故障，但延迟、数据一致性和运维复杂度都更高。</p><p>常见做法是按用户、地域、业务单元分流。比如华东用户主要访问华东，华北用户主要访问华北，每个用户的写入尽量固定到一个主区域，减少跨地域写冲突。</p><p>全量多地同时写同一份强一致数据很难。很多系统会选择“业务分片双活”，避免所有请求随意打到任意城市。</p><h2 id="六、两地三中心" tabindex="-1">六、两地三中心 <a class="header-anchor" href="#六、两地三中心" aria-label="Permalink to &quot;六、两地三中心&quot;">​</a></h2><p>两地三中心是一种传统企业容灾形态：同城两个中心，加上异地一个灾备中心。</p><table tabindex="0"><thead><tr><th>中心</th><th>作用</th></tr></thead><tbody><tr><td>同城生产中心</td><td>承载主要业务</td></tr><tr><td>同城灾备中心</td><td>低延迟接管，处理本地中心故障</td></tr><tr><td>异地灾备中心</td><td>处理城市级灾难</td></tr></tbody></table><p>同城中心之间可以做同步或准同步复制，异地中心通常做异步复制。这样既兼顾本地高可用，也保留异地恢复能力。</p><h2 id="七、多活的代价" tabindex="-1">七、多活的代价 <a class="header-anchor" href="#七、多活的代价" aria-label="Permalink to &quot;七、多活的代价&quot;">​</a></h2><p>多活听起来很稳，实际会牵动多套系统一起变化。入口流量、用户归属、数据写入、缓存一致性、消息队列、定时任务、文件上传、后台任务都要设计清楚。</p><p>常见风险：</p><table tabindex="0"><thead><tr><th>风险</th><th>表现</th></tr></thead><tbody><tr><td>写冲突</td><td>两个机房同时修改同一数据</td></tr><tr><td>缓存不一致</td><td>用户在不同机房看到不同状态</td></tr><tr><td>消息重复</td><td>两边都消费同一事件</td></tr><tr><td>任务重复执行</td><td>定时任务在多个机房同时跑</td></tr><tr><td>切换不完整</td><td>页面切过去了，后端或数据库没切过去</td></tr></tbody></table><p>容灾架构要靠演练确认。文档里写着“异地可切换”，和真实把流量切到异地、确认登录、下单、支付、后台任务、报表都可用，是两回事。</p><p>高可用和容灾最终都要落到 RTO、RPO、切换路径、数据恢复和演练记录上。</p>',36)])])}const A=d(h,[["render",o]]);export{c as __pageData,A as default};
